import { KeyboardControls, type KeyboardControlsEntry } from '@react-three/drei'
import { Canvas } from '@react-three/fiber'
import { Physics } from '@react-three/rapier'
import { type ReactNode, useMemo } from 'react'
import { WorldContext } from './context'
import { keyboardMap as defaultKeyboardMap } from './keyboard'
import { DEFAULT_PALETTE, type WorldPalette } from './palette'
import type { Vec3, WorldFog } from './types'

export interface WorldProps {
  unit?: number
  gravity?: Vec3
  keyboardMap?: KeyboardControlsEntry[]
  /** Render the default light rig. Set false to supply your own (e.g. <LightRig>). */
  lights?: boolean
  /** Override color slots; unset slots keep their defaults. Components read these via `useWorld()`. */
  palette?: Partial<WorldPalette>
  /** Linear distance fog. Pair the color with your sky's horizon. */
  fog?: WorldFog
  /** Fired when a pointer click misses every object (used to deselect in the editor). */
  onPointerMissed?: () => void
  debug?: boolean
  children?: ReactNode
}

export function World({
  unit = 1,
  gravity = [0, -9.81, 0],
  keyboardMap = defaultKeyboardMap,
  lights = true,
  palette,
  fog,
  onPointerMissed,
  debug = false,
  children,
}: WorldProps) {
  const context = useMemo(
    () => ({ unit, gravity, palette: { ...DEFAULT_PALETTE, ...palette } }),
    [unit, gravity, palette],
  )

  return (
    <KeyboardControls map={keyboardMap}>
      <Canvas shadows camera={{ position: [6, 4, 6], fov: 60 }} onPointerMissed={onPointerMissed}>
        <WorldContext.Provider value={context}>
          {fog && <fog attach="fog" args={[fog.color, fog.near * unit, fog.far * unit]} />}
          {lights && (
            <>
              <ambientLight intensity={0.6} />
              <directionalLight
                position={[12, 18, 8]}
                intensity={1.6}
                castShadow
                shadow-mapSize={[2048, 2048]}
                shadow-camera-near={1}
                shadow-camera-far={60}
                shadow-camera-left={-25}
                shadow-camera-right={25}
                shadow-camera-top={25}
                shadow-camera-bottom={-25}
              />
            </>
          )}
          <Physics gravity={gravity} debug={debug}>
            {children}
          </Physics>
        </WorldContext.Provider>
      </Canvas>
    </KeyboardControls>
  )
}

import { OrbitControls, TransformControls } from '@react-three/drei'
import { Leva, useControls } from 'leva'
import { type CSSProperties, useEffect, useRef, useState } from 'react'
import type { Object3D } from 'three'
import type { Vec3 } from './types'
import { World, type WorldProps } from './World'
import {
  type ComponentRegistry,
  type JsonValue,
  serializeWorld,
  type WorldData,
  type WorldNode,
} from './world-data'

type TransformMode = 'translate' | 'rotate'
type Selection = { index: number; object: Object3D } | null

export interface WorldEditorProps
  extends Omit<WorldProps, 'children' | 'unit' | 'gravity' | 'palette' | 'fog'> {
  data: WorldData
  registry: ComponentRegistry
  onChange: (next: WorldData) => void
}

/** Nodes rendered without a transform (no meaningful position to gizmo). */
const NON_SELECTABLE = new Set(['Sky', 'LightRig'])
/** Nodes skipped in the editor (no FPS controller while orbiting). */
const SKIPPED = new Set(['Player'])

const HISTORY_LIMIT = 100

const asVec3 = (value: JsonValue | undefined): Vec3 | undefined =>
  Array.isArray(value) && value.length === 3 ? (value as unknown as Vec3) : undefined

const isTyping = (target: EventTarget | null) => {
  const el = target as HTMLElement | null
  return !!el && (el.tagName === 'INPUT' || el.tagName === 'TEXTAREA' || el.isContentEditable)
}

/**
 * Edit a world data-first: orbit camera, click-select, gizmo move/rotate, leva props,
 * add/duplicate/delete nodes, undo — all writing back to `WorldData`.
 */
export function WorldEditor({ data, registry, onChange, ...worldProps }: WorldEditorProps) {
  const [selected, setSelected] = useState<Selection>(null)
  const [mode, setMode] = useState<TransformMode>('translate')
  const history = useRef<WorldData[]>([])

  /** Commit a change, recording the previous state for undo. */
  const apply = (next: WorldData) => {
    history.current.push(data)
    if (history.current.length > HISTORY_LIMIT) history.current.shift()
    onChange(next)
  }

  const undo = () => {
    const prev = history.current.pop()
    if (!prev) return
    setSelected(null)
    onChange(prev)
  }

  const patchNode = (index: number, patch: Record<string, JsonValue>) => {
    const nodes = data.nodes.map((node, i) =>
      i === index ? { ...node, props: { ...node.props, ...patch } } : node,
    )
    apply({ ...data, nodes })
  }

  const addNode = (type: string) => {
    apply({ ...data, nodes: [...data.nodes, { type, props: { position: [0, 0, 0] } }] })
    setSelected(null)
  }

  const duplicateSelected = () => {
    if (!selected) return
    const source = data.nodes[selected.index]
    const copy: WorldNode = JSON.parse(JSON.stringify(source))
    const at = asVec3(copy.props?.position) ?? [0, 0, 0]
    copy.props = { ...copy.props, position: [at[0] + 0.5, at[1], at[2] + 0.5] }
    apply({ ...data, nodes: [...data.nodes, copy] })
    setSelected(null)
  }

  const deleteSelected = () => {
    if (!selected) return
    apply({ ...data, nodes: data.nodes.filter((_, i) => i !== selected.index) })
    setSelected(null)
  }

  const commitTransform = () => {
    if (!selected) return
    const { position, rotation } = selected.object
    const r = (n: number) => Math.round(n * 1000) / 1000
    patchNode(selected.index, {
      position: [r(position.x), r(position.y), r(position.z)],
      rotation: [r(rotation.x), r(rotation.y), r(rotation.z)],
    })
  }

  useEffect(() => {
    const onKey = (event: KeyboardEvent) => {
      if (isTyping(event.target)) return
      if ((event.metaKey || event.ctrlKey) && event.key === 'z') {
        event.preventDefault()
        undo()
        return
      }
      if (event.key === 'Escape') setSelected(null)
      else if (event.key === 'g') setMode('translate')
      else if (event.key === 'r') setMode('rotate')
      else if (event.key === 'd') duplicateSelected()
      else if (event.key === 'Delete' || event.key === 'Backspace') deleteSelected()
    }
    window.addEventListener('keydown', onKey)
    return () => window.removeEventListener('keydown', onKey)
  }, [data, selected, onChange])

  return (
    <>
      <World
        {...worldProps}
        unit={data.unit}
        gravity={data.gravity}
        palette={data.palette}
        fog={data.fog}
        onPointerMissed={() => setSelected(null)}
      >
        <OrbitControls makeDefault />
        <EditableNodes
          nodes={data.nodes}
          registry={registry}
          onSelect={(index, object) => setSelected({ index, object })}
        />
        {selected && (
          <TransformControls object={selected.object} mode={mode} onMouseUp={commitTransform} />
        )}
      </World>

      <Leva hidden={selected === null} />
      <EditorToolbar
        mode={mode}
        onMode={setMode}
        data={data}
        registry={registry}
        selected={selected?.index ?? null}
        canUndo={history.current.length > 0}
        onAdd={addNode}
        onDuplicate={duplicateSelected}
        onDelete={deleteSelected}
        onUndo={undo}
      />
      {selected !== null && (
        <NodeControls
          index={selected.index}
          node={data.nodes[selected.index]}
          onPatch={patchNode}
        />
      )}
    </>
  )
}

interface EditableNodesProps {
  nodes: WorldNode[]
  registry: ComponentRegistry
  onSelect: (index: number, object: Object3D) => void
}

function EditableNodes({ nodes, registry, onSelect }: EditableNodesProps) {
  return (
    <>
      {nodes.map((node, index) => {
        if (SKIPPED.has(node.type)) return null
        const Component = registry[node.type]
        if (!Component) return null

        if (NON_SELECTABLE.has(node.type)) {
          return <Component key={index} {...node.props} />
        }

        const { position, rotation, ...rest } = node.props ?? {}
        return (
          // biome-ignore lint/a11y/noStaticElementInteractions: <group> is a three.js object, not a DOM element
          <group
            key={index}
            position={asVec3(position) ?? [0, 0, 0]}
            rotation={asVec3(rotation) ?? [0, 0, 0]}
            onClick={(event) => {
              event.stopPropagation()
              onSelect(index, event.eventObject)
            }}
          >
            <Component {...rest} />
          </group>
        )
      })}
    </>
  )
}

interface NodeControlsProps {
  index: number
  node: WorldNode
  onPatch: (index: number, patch: Record<string, JsonValue>) => void
}

function NodeControls({ index, node, onPatch }: NodeControlsProps) {
  const props = node.props ?? {}
  const position = asVec3(props.position) ?? [0, 0, 0]
  const rotation = asVec3(props.rotation) ?? [0, 0, 0]
  const seed = typeof props.seed === 'number' ? props.seed : undefined

  useControls(
    `${node.type} #${index}`,
    () => ({
      position: {
        value: { x: position[0], y: position[1], z: position[2] },
        step: 0.1,
        onChange: (
          v: { x: number; y: number; z: number },
          _path: string,
          ctx: { initial: boolean },
        ) => {
          if (!ctx.initial) onPatch(index, { position: [v.x, v.y, v.z] })
        },
      },
      rotation: {
        value: { x: rotation[0], y: rotation[1], z: rotation[2] },
        step: 0.05,
        onChange: (
          v: { x: number; y: number; z: number },
          _path: string,
          ctx: { initial: boolean },
        ) => {
          if (!ctx.initial) onPatch(index, { rotation: [v.x, v.y, v.z] })
        },
      },
      ...(seed !== undefined
        ? {
            seed: {
              value: seed,
              step: 1,
              onChange: (v: number, _path: string, ctx: { initial: boolean }) => {
                if (!ctx.initial) onPatch(index, { seed: Math.round(v) })
              },
            },
          }
        : {}),
    }),
    [index],
  )

  return null
}

const TOOLBAR: CSSProperties = {
  position: 'fixed',
  top: '1rem',
  left: '1rem',
  display: 'flex',
  gap: '0.45rem',
  alignItems: 'center',
  zIndex: 10,
  padding: '0.45rem 0.6rem',
  borderRadius: 10,
  background: 'rgba(7, 11, 17, 0.82)',
  border: '1px solid #15202a',
  backdropFilter: 'blur(8px)',
  fontFamily: 'ui-monospace, SF Mono, Menlo, monospace',
}

const button = (active: boolean, disabled = false): CSSProperties => ({
  padding: '0.35rem 0.65rem',
  borderRadius: 6,
  border: `1px solid ${active ? 'rgba(61, 245, 138, 0.5)' : '#15202a'}`,
  cursor: disabled ? 'default' : 'pointer',
  background: active ? 'rgba(61, 245, 138, 0.14)' : 'rgba(255, 255, 255, 0.04)',
  color: disabled ? '#5f7d75' : active ? '#3df58a' : '#cfe6db',
  opacity: disabled ? 0.5 : 1,
  fontSize: '0.78rem',
  fontFamily: 'inherit',
})

const SELECT: CSSProperties = {
  ...button(false),
  appearance: 'none',
  paddingRight: '0.9rem',
}

const DIVIDER: CSSProperties = {
  width: 1,
  alignSelf: 'stretch',
  background: '#15202a',
}

const HINT: CSSProperties = {
  color: '#5f7d75',
  fontSize: '0.72rem',
  paddingLeft: '0.2rem',
}

interface EditorToolbarProps {
  mode: TransformMode
  onMode: (mode: TransformMode) => void
  data: WorldData
  registry: ComponentRegistry
  selected: number | null
  canUndo: boolean
  onAdd: (type: string) => void
  onDuplicate: () => void
  onDelete: () => void
  onUndo: () => void
}

function EditorToolbar({
  mode,
  onMode,
  data,
  registry,
  selected,
  canUndo,
  onAdd,
  onDuplicate,
  onDelete,
  onUndo,
}: EditorToolbarProps) {
  const hasSelection = selected !== null

  const exportWorld = async () => {
    const text = serializeWorld(data)
    try {
      await navigator.clipboard.writeText(text)
    } catch {
      // clipboard may be unavailable; the log below is the fallback
    }
    console.log(text)
  }

  return (
    <div style={TOOLBAR}>
      <button
        type="button"
        style={button(mode === 'translate')}
        onClick={() => onMode('translate')}
        title="Move (g)"
      >
        Move
      </button>
      <button
        type="button"
        style={button(mode === 'rotate')}
        onClick={() => onMode('rotate')}
        title="Rotate (r)"
      >
        Rotate
      </button>

      <span style={DIVIDER} />

      <select
        style={SELECT}
        value=""
        onChange={(event) => {
          if (event.target.value) onAdd(event.target.value)
          event.target.value = ''
        }}
        title="Insert a component at the origin"
      >
        <option value="">+ Add…</option>
        {Object.keys(registry)
          .sort()
          .map((name) => (
            <option key={name} value={name}>
              {name}
            </option>
          ))}
      </select>
      <button
        type="button"
        style={button(false, !hasSelection)}
        disabled={!hasSelection}
        onClick={onDuplicate}
        title="Duplicate selection (d)"
      >
        Duplicate
      </button>
      <button
        type="button"
        style={button(false, !hasSelection)}
        disabled={!hasSelection}
        onClick={onDelete}
        title="Delete selection (⌫)"
      >
        Delete
      </button>
      <button
        type="button"
        style={button(false, !canUndo)}
        disabled={!canUndo}
        onClick={onUndo}
        title="Undo (⌘Z)"
      >
        Undo
      </button>

      <span style={DIVIDER} />

      <button type="button" style={button(false)} onClick={exportWorld}>
        Export JSON
      </button>
      <span style={HINT}>
        {selected === null ? 'click a component · Esc deselects' : `selected #${selected}`}
      </span>
    </div>
  )
}

import type { ComponentRegistry, WorldNode } from './world-data'

export interface WorldNodesProps {
  nodes: WorldNode[]
  registry: ComponentRegistry
}

/** Render a list of world nodes by looking each `type` up in the registry. Recurses into children. */
export function WorldNodes({ nodes, registry }: WorldNodesProps) {
  return (
    <>
      {nodes.map((node, index) => {
        const Component = registry[node.type]
        if (!Component) {
          console.warn(`[runek] Unknown component "${node.type}" — skipped.`)
          return null
        }
        const children = node.children?.length ? (
          <WorldNodes nodes={node.children} registry={registry} />
        ) : null
        return (
          <Component key={index} {...node.props}>
            {children}
          </Component>
        )
      })}
    </>
  )
}

import { World, type WorldProps } from './World'
import { WorldNodes } from './WorldNodes'
import type { ComponentRegistry, WorldData } from './world-data'

export interface WorldRendererProps
  extends Omit<WorldProps, 'children' | 'unit' | 'gravity' | 'palette' | 'fog'> {
  data: WorldData
  registry: ComponentRegistry
}

/** Render a `WorldData` object inside a `<World>`, resolving each node via the registry. */
export function WorldRenderer({ data, registry, ...worldProps }: WorldRendererProps) {
  return (
    <World
      unit={data.unit}
      gravity={data.gravity}
      palette={data.palette}
      fog={data.fog}
      {...worldProps}
    >
      <WorldNodes nodes={data.nodes} registry={registry} />
    </World>
  )
}

/**
 * Named color slots shared by the whole world. Components default their colors
 * to these slots, so swapping the palette re-themes every component at once —
 * explicit color props still win.
 */
export interface WorldPalette {
  /** Furniture frames, table tops, doors. */
  wood: string
  /** Shelf backs and other shaded wood. */
  woodDark: string
  /** Walls and rooms. */
  wall: string
  /** Interior floors. */
  floor: string
  roof: string
  /** Stairs and masonry. */
  stone: string
  /** Terrain ground cover. */
  ground: string
  /** Leaves and grass. */
  foliage: string
  /** Tree trunks and branches. */
  bark: string
  /** Shores and beaches. */
  sand: string
  /** Rugs and upholstery. */
  fabric: string
  /** Trim, knobs, rug borders. */
  accent: string
  /** Lamp poles and hardware. */
  metal: string
  waterDeep: string
  waterShallow: string
}

export const DEFAULT_PALETTE: WorldPalette = {
  wood: '#6b4f3a',
  woodDark: '#5c4330',
  wall: '#cfc7ba',
  floor: '#b8a98f',
  roof: '#8a5a44',
  stone: '#9a8c78',
  ground: '#3a4a3f',
  foliage: '#4f7a3a',
  bark: '#5b4636',
  sand: '#d8c79a',
  fabric: '#7a3b3b',
  accent: '#caa24a',
  metal: '#39383a',
  waterDeep: '#13415c',
  waterShallow: '#3f86a8',
}

export type Rng = () => number

/** Deterministic seeded RNG: a given seed always yields the same sequence in [0, 1). */
export function rng(seed: number): Rng {
  let s = seed >>> 0
  return () => {
    s = Math.imul(s ^ (s >>> 15), 1 | s)
    s ^= s + Math.imul(s ^ (s >>> 7), 61 | s)
    return ((s ^ (s >>> 14)) >>> 0) / 4294967296
  }
}

export const range = (r: Rng, min: number, max: number) => min + r() * (max - min)

export const int = (r: Rng, min: number, max: number) => Math.floor(range(r, min, max + 1))

export const pick = <T>(r: Rng, items: readonly T[]): T => items[Math.floor(r() * items.length)]

/** Derive a stable child seed, so nested components stay deterministic. */
export const sub = (seed: number, n: number) => (Math.imul(seed >>> 0, 0x9e3779b1) + n) >>> 0

import type { WorldPalette } from './palette'

export type Vec3 = [number, number, number]

/** The contract every Runek component implements. */
export interface WorldComponentProps {
  position?: Vec3
  rotation?: Vec3
  seed?: number
}

/** Linear distance fog over the whole world. */
export interface WorldFog {
  color: string
  /** Distance where the fog starts, in units. */
  near: number
  /** Distance where the fog fully obscures, in units. */
  far: number
}

export interface WorldContextValue {
  /** Meters per unit. Components scale their geometry by this. */
  unit: number
  gravity: Vec3
  /** Resolved color slots components default their materials to. */
  palette: WorldPalette
}

import { useContext } from 'react'
import { WorldContext } from './context'

export const useWorld = () => useContext(WorldContext)

import type { ComponentType } from 'react'
import type { WorldPalette } from './palette'
import type { Vec3, WorldFog } from './types'

export type JsonValue =
  | string
  | number
  | boolean
  | null
  | JsonValue[]
  | { [key: string]: JsonValue }

/** One placed component: a registry key, its props, and optional nested children. */
export interface WorldNode {
  /** Registry key — the component's name, e.g. "Bookshelf". */
  type: string
  props?: Record<string, JsonValue>
  children?: WorldNode[]
}

/** A whole world as plain data — diffable, forkable, version-controlled like any file. */
export interface WorldData {
  version: 1
  unit?: number
  gravity?: Vec3
  /** Color-slot overrides applied to every component in the world. */
  palette?: Partial<WorldPalette>
  fog?: WorldFog
  nodes: WorldNode[]
}

// biome-ignore lint/suspicious/noExplicitAny: a registry holds components with heterogeneous prop types
export type ComponentRegistry = Record<string, ComponentType<any>>

/** Serialize a world to pretty JSON text. */
export function serializeWorld(data: WorldData): string {
  return `${JSON.stringify(data, null, 2)}\n`
}

/** Parse and lightly validate world JSON text. Throws on an unsupported shape. */
export function parseWorld(json: string): WorldData {
  const data = JSON.parse(json) as WorldData
  if (data.version !== 1) {
    throw new Error(
      `Unsupported world version: ${JSON.stringify((data as { version?: unknown }).version)}`,
    )
  }
  if (!Array.isArray(data.nodes)) {
    throw new Error('World data must have a "nodes" array')
  }
  return data
}
